import{c as l,Q as i,j as r,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const _=JSON.parse('{"title":"出使锡耶纳","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/53-出使锡耶纳.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/53-出使锡耶纳.md"}'),c={name:"research/machiavelli/machiavelli/diplomatic/lower/53-出使锡耶纳.md"};function o(s,a,n,m,d,p){return i(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"出使锡耶纳",tabindex:"-1"},[t("出使锡耶纳 "),e("a",{class:"header-anchor",href:"#出使锡耶纳","aria-label":'Permalink to "出使锡耶纳"'},"​")],-1),e("p",null,"出使锡耶纳 信件3",-1),e("p",null,"诸位大人钧鉴： 我在12日给诸位大人写过信，并于昨天早晨由信使匆匆寄出。我在该 信中向你们报告说，特使将于近日到达这里，他在锡耶纳地区都是自己 承担花销，他的随从不多于110名骑士、30头驮运的骡子以及约40名步行 者；他会与四五十名骑士一起住在主教宫，剩下的人会在不同的旅舍中下 榻，其花费则由市政当局支付；我得知他会在周一或周二离开此地。自那 之后，特使抵达了这里，并住在我信中所说的地方。不过，他没有自己支 付开销。人们按照接待使节的惯例，以执政团的名义向他呈上各类食物。 但是，那些食物的规格比惯例更奢侈，据说要花费100多达克特。不过， 除此之外，他们没有做更多的招待，而是让特使一行自己照料自己。特使 将在周一早晨离开这里，并前往波吉邦西。他将在周二前往圣卡夏诺。据 他自己说，他计划在周三抵达佛罗伦萨。我从好几个人那里都听说，特 使在吃饭时公开说过这话，因此没理由对此加以怀疑。在我看来，我目前在 这里没有什么可做的了，所以我将于明天早上离开，然后从容地直奔佛罗伦 萨。在路上的时候，如果诸位大人想委派给我什么其他任务，请让我知晓。 在此地时，我从西班牙人那里听说了一些事，认为有必要告诉诸位大 人。事情是这样的。大约1个月前，这里收到了2封皇帝从德意志发来的 信，分别寄给巴利阿和潘多尔福。信的内容是相同的，即告诉他们皇帝将 驾临意大利。他相信这座城市会表现出善意，还建议他们不要再按照协议 付钱给法国国王，并向法国表明，由于该协议拂逆了皇帝，所以是无效 的。除上述内容外，寄给潘多尔福的信里还有许多具体的指示。潘多尔福 把这些内容拿给了巴利阿和其他人看，并且显得非常自豪。 据我所知，就像任何家境富有从而不愿劳作的人一样，潘多尔福其实 压根就不希望皇帝来到这里。某一天，他曾对他的一个朋友说： “如果皇 帝来了，除了比萨人以外，谁也得不到好处。”但潘多尔福并不认为皇帝",-1),e("p",null,"马基雅维利全集 Opere complete di Niccolò Machiavelli",-1)])])}const f=l(c,[["render",o]]);export{_ as __pageData,f as default};
